#!/usr/bin/env node
/**
 * scripts/sync-ide-rules.mjs
 *
 * Generator: .claude/rules/*.md       ->  .cursor/rules/*.mdc
 * Generator: .claude/skills/(name)/SKILL.md  ->  .cursor/commands/(name).md
 *
 * Single source of truth is .claude/. Cursor IDE artifacts are
 * generated so contributors using either IDE experience the same rails.
 *
 * Modes:
 *   --check     fail with exit 1 if any generated file would differ from
 *               what currently exists on disk (used by pre-commit-ide-parity)
 *   --write     write the generated files (default when no flag given)
 *
 * Zero external dependencies: Node built-ins only.
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(SCRIPT_DIR, "..");

const RULES_DIR = path.join(REPO_ROOT, ".claude/rules");
const SKILLS_DIR = path.join(REPO_ROOT, ".claude/skills");
const CURSOR_RULES_DIR = path.join(REPO_ROOT, ".cursor/rules");
const CURSOR_COMMANDS_DIR = path.join(REPO_ROOT, ".cursor/commands");

const GENERATED_HEADER =
  "<!-- GENERATED by scripts/sync-ide-rules.mjs from .claude/. Do not edit by hand. -->\n";

function main() {
  const args = new Set(process.argv.slice(2));
  const check = args.has("--check");
  const write = !check;

  const plan = [];

  // Rules → .cursor/rules/*.mdc
  for (const file of readMarkdown(RULES_DIR)) {
    if (file.name === "README.md") continue;
    const { frontmatter, body } = parseFrontmatter(file.content);
    const mdc = renderRuleMdc(frontmatter, body);
    const out = path.join(CURSOR_RULES_DIR, file.name.replace(/\.md$/, ".mdc"));
    plan.push({ source: file.path, target: out, content: mdc });
  }

  // Skills → .cursor/commands/*.md
  for (const dirent of fs.readdirSync(SKILLS_DIR, { withFileTypes: true })) {
    if (!dirent.isDirectory()) continue;
    const skillFile = path.join(SKILLS_DIR, dirent.name, "SKILL.md");
    if (!fs.existsSync(skillFile)) continue;
    const content = fs.readFileSync(skillFile, "utf8");
    const { frontmatter, body } = parseFrontmatter(content);
    const cmd = renderCommandMd(dirent.name, frontmatter, body);
    const out = path.join(CURSOR_COMMANDS_DIR, dirent.name + ".md");
    plan.push({ source: skillFile, target: out, content: cmd });
  }

  // Drift of obsolete files
  const expectedTargets = new Set(plan.map((p) => p.target));
  const orphanRules = collectOrphans(CURSOR_RULES_DIR, expectedTargets);
  const orphanCmds = collectOrphans(CURSOR_COMMANDS_DIR, expectedTargets);

  if (check) {
    const diffs = plan
      .map((p) => ({
        target: p.target,
        changed: fileDiffers(p.target, p.content),
      }))
      .filter((d) => d.changed);
    const problems = diffs.map((d) => `would update: ${relFromRoot(d.target)}`);
    for (const o of [...orphanRules, ...orphanCmds])
      problems.push(`would delete:   ${relFromRoot(o)}`);
    if (problems.length === 0) {
      console.log("sync-ide-rules: in sync ✓");
      process.exit(0);
    }
    console.error("sync-ide-rules: drift detected");
    for (const p of problems) console.error("  " + p);
    console.error("\nRun: node scripts/sync-ide-rules.mjs");
    process.exit(1);
  }

  if (write) {
    ensureDir(CURSOR_RULES_DIR);
    ensureDir(CURSOR_COMMANDS_DIR);

    let wrote = 0;
    for (const { target, content } of plan) {
      ensureDir(path.dirname(target));
      if (fileDiffers(target, content)) {
        fs.writeFileSync(target, content, "utf8");
        wrote++;
      }
    }

    let deleted = 0;
    for (const orphan of [...orphanRules, ...orphanCmds]) {
      fs.unlinkSync(orphan);
      deleted++;
    }

    console.log(`sync-ide-rules: wrote ${wrote}, deleted ${deleted}`);
  }
}

function readMarkdown(dir) {
  if (!fs.existsSync(dir)) return [];
  return fs
    .readdirSync(dir, { withFileTypes: true })
    .filter((d) => d.isFile() && d.name.endsWith(".md"))
    .map((d) => {
      const full = path.join(dir, d.name);
      return {
        name: d.name,
        path: full,
        content: fs.readFileSync(full, "utf8"),
      };
    });
}

function parseFrontmatter(source) {
  if (!source.startsWith("---\n")) return { frontmatter: {}, body: source };
  const end = source.indexOf("\n---", 4);
  if (end === -1) return { frontmatter: {}, body: source };
  const raw = source.slice(4, end);
  const body = source.slice(end + 4).replace(/^\n/, "");
  return { frontmatter: parseYaml(raw), body };
}

function parseYaml(src) {
  const out = {};
  const lines = src.split("\n");
  let key = null;
  let listAcc = null;
  for (const line of lines) {
    if (!line.trim() || line.trim().startsWith("#")) continue;
    const arrayItem = line.match(/^\s+-\s+(.*)$/);
    if (arrayItem && key !== null && listAcc !== null) {
      listAcc.push(stripQuotes(arrayItem[1]));
      continue;
    }
    const match = line.match(/^([A-Za-z_][\w-]*):\s*(.*)$/);
    if (!match) continue;
    const [, k, v] = match;
    if (v === "" || v === "|") {
      key = k;
      listAcc = [];
      out[k] = listAcc;
      continue;
    }
    if (v.startsWith("[") && v.endsWith("]")) {
      out[k] = v
        .slice(1, -1)
        .split(",")
        .map((s) => stripQuotes(s.trim()))
        .filter(Boolean);
      key = null;
      listAcc = null;
      continue;
    }
    out[k] = stripQuotes(v);
    key = null;
    listAcc = null;
  }
  return out;
}

function stripQuotes(s) {
  if (!s) return "";
  if (
    (s.startsWith('"') && s.endsWith('"')) ||
    (s.startsWith("'") && s.endsWith("'"))
  ) {
    return s.slice(1, -1);
  }
  return s;
}

function renderRuleMdc(frontmatter, body) {
  const globs = Array.isArray(frontmatter.scope)
    ? frontmatter.scope.join(", ")
    : "";
  const description = frontmatter.applies_when || frontmatter.name || "";
  const alwaysApply = globs === "";
  const header = [
    "---",
    `description: ${description}`,
    `globs: ${globs}`,
    `alwaysApply: ${alwaysApply}`,
    "---",
    "",
  ].join("\n");
  return GENERATED_HEADER + header + body.trimEnd() + "\n";
}

function renderCommandMd(name, frontmatter, body) {
  const description = frontmatter.description || "";
  const model = frontmatter.model || "";
  const header = [
    "---",
    `description: ${description}`,
    model ? `model: ${model}` : "",
    "---",
    "",
  ]
    .filter((l) => l !== null)
    .join("\n");
  const note = `> Cursor-side mirror of \`/${name}\`. Source of truth: \`.claude/skills/${name}/SKILL.md\`.\n\n`;
  return GENERATED_HEADER + header + note + body.trimEnd() + "\n";
}

function fileDiffers(target, content) {
  if (!fs.existsSync(target)) return true;
  return fs.readFileSync(target, "utf8") !== content;
}

function ensureDir(dir) {
  fs.mkdirSync(dir, { recursive: true });
}

function collectOrphans(dir, expected) {
  if (!fs.existsSync(dir)) return [];
  return fs
    .readdirSync(dir, { withFileTypes: true })
    .filter((d) => d.isFile())
    .map((d) => path.join(dir, d.name))
    .filter((p) => !expected.has(p));
}

function relFromRoot(abs) {
  return path.relative(REPO_ROOT, abs).split(path.sep).join("/");
}

main();
